solutions.python:
class Solution:
    def fix_grid(self, css_string: str) -> str:
        css_string = css_string.replace('grid-auto-rows: 100px;', 'grid-auto-rows: max-content;')
        return css_string

s = Solution()
print(s.fix_grid(".grid-container {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  grid-auto-rows: 100px;
  grid-auto-flow: row;
}
.grid-item {
  background-color: #8a2be2;
  height: 50px;
}"))

